// === Maeve/Elara/Amara ? Instagram comments parser + self-reply filter ===
// Code node mode: "Run Once for All Items"

const items = $input.all();

// Map IG Business Account ID -> girl's name
const OWNERS = {
  '17841478136820581': 'Maeve',
  '17841480189765921': 'Elara',
  '17841480706715642': 'Amara',
};

const OWNER_OVERRIDE = ''; // optional: force an owner id, leave '' to auto-detect

function getPayload(item) {
  const j = item.json || {};
  return j.body !== undefined ? j.body : j;
}

function extractChanges(payload) {
  const out = [];
  const blocks = Array.isArray(payload) ? payload : [payload];

  for (const block of blocks) {
    if (!block || typeof block !== 'object') continue;

    // Shape A ? flattened shape
    if (block.value && (block.field === 'comments' || block.value.text !== undefined)) {
      out.push({ ownerId: String(block.id ?? ''), value: block.value, time: block.time });
      continue;
    }

    // Shape B ? standard IG graph webhook
    if (Array.isArray(block.entry)) {
      for (const entry of block.entry) {
        for (const change of (entry.changes || [])) {
          if (change.field !== 'comments') continue;
          out.push({ ownerId: String(entry.id ?? ''), value: change.value, time: entry.time });
        }
      }
    }
  }
  return out;
}

const results = [];

for (const item of items) {
  for (const c of extractChanges(getPayload(item))) {
    const v = c.value || {};
    const from = v.from || {};

    const commenterId   = String(from.id ?? '');
    const commenterName = from.username ?? '';
    const commentId     = String(v.id ?? '');
    const text          = (v.text ?? '').trim();
    const mediaId       = String(v.media?.id ?? '');
    const ownerId       = OWNER_OVERRIDE || c.ownerId;
    const ownerName     = OWNERS[ownerId] || 'Unknown';   // <-- new

    const timeISO = DateTime.fromSeconds(Number(c.time)).toISO();              // 2026-06-...T...+00:00
    const timeReadable = DateTime.fromSeconds(Number(c.time)).toFormat('yyyy-MM-dd HH:mm:ss');

    // Skip self-comments (owner === commenter) + loop prevention
    if (ownerId && commenterId && ownerId === commenterId) {
      console.log(`Skip self-comment from @${commenterName} on ${ownerName}'s post`);
      continue;
    }

    // Skip empty / non-comment events
    if (!commentId || !text) {
      console.log('Skip: missing comment id or empty text');
      continue;
    }

    results.push({
      json: {
        commentId,
        text,
        commenterId,
        commenterName,
        mediaId,
        ownerId,
        ownerName,        // <-- new
        time: timeReadable,    // human-readable instead of epoch
        timeISO,               // ISO version (handy for sorting/databases)
      },
    });
  }
}

return results;

